-- ═══════════════════════════════════════════════════════════════════════════
-- MEIRINS · Tabla diets — ejecutar en Supabase SQL Editor
-- ═══════════════════════════════════════════════════════════════════════════

CREATE TABLE IF NOT EXISTS diets (
  id                   TEXT        PRIMARY KEY,
  display_order        INT         NOT NULL,
  icon                 TEXT,
  category             TEXT        NOT NULL,
  name                 JSONB       NOT NULL,
  description          JSONB,
  allowed_foods        JSONB,
  forbidden_foods      JSONB,
  limited_foods        JSONB,
  macros               JSONB,
  calories_note        JSONB,
  benefits             JSONB,
  warnings             JSONB,
  compatible_goals     TEXT[]      DEFAULT '{}',
  good_for_conditions  TEXT[]      DEFAULT '{}',
  avoid_for_conditions TEXT[]      DEFAULT '{}',
  allergen_free        TEXT[]      DEFAULT '{}',
  fasting_window       JSONB,
  sample_day           JSONB,
  created_at           TIMESTAMPTZ DEFAULT NOW(),
  updated_at           TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS diets_category_idx   ON diets (category);
CREATE INDEX IF NOT EXISTS diets_goals_idx      ON diets USING gin (compatible_goals);
CREATE INDEX IF NOT EXISTS diets_cond_idx       ON diets USING gin (good_for_conditions);
CREATE INDEX IF NOT EXISTS diets_allerg_idx     ON diets USING gin (allergen_free);

ALTER TABLE diets ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "diets_public_read" ON diets;
CREATE POLICY "diets_public_read" ON diets FOR SELECT USING (true);

