-- ── 7. LOW FODMAP ────────────────────────────────────────────────────────────
INSERT INTO diets (id,display_order,icon,category,name,description,allowed_foods,forbidden_foods,limited_foods,macros,benefits,warnings,compatible_goals,good_for_conditions,allergen_free,sample_day)
VALUES (
'low_fodmap',7,'🫙','therapeutic',
'{"es":"Low FODMAP","en":"Low FODMAP","fr":"Low FODMAP","it":"Low FODMAP"}',
'{"es":"Reduce los carbohidratos fermentables para aliviar el síndrome de intestino irritable. Se hace en 3 fases: eliminación, reintroducción y personalización.","en":"Reduces fermentable carbohydrates to relieve irritable bowel syndrome. Done in 3 phases: elimination, reintroduction and personalisation.","fr":"Réduit les glucides fermentescibles pour soulager le syndrome de l''intestin irritable. Se fait en 3 phases.","it":"Riduce i carboidrati fermentabili per alleviare la sindrome dell''intestino irritabile. Si svolge in 3 fasi."}',
'{"es":["Arroz, quinoa, avena (porción controlada)","Pollo, pavo, pescados, huevos","Lactosa reducida: quesos curados, leche sin lactosa","Verduras bajas en FODMAP: zanahoria, pepino, tomate, espinacas","Frutas: kiwi, naranja, fresa, arándanos","Frutos secos (nueces, nueces de macadamia, en pequeñas cantidades)"],"en":["Rice, quinoa, oats (controlled portion)","Chicken, turkey, fish, eggs","Low-lactose: aged cheeses, lactose-free milk","Low-FODMAP vegetables: carrot, cucumber, tomato, spinach","Fruits: kiwi, orange, strawberry, blueberries","Nuts (walnuts, macadamia, in small amounts)"],"fr":["Riz, quinoa, avoine (portion contrôlée)","Poulet, dinde, poissons, œufs","Faible en lactose: fromages affinés, lait sans lactose","Légumes faibles en FODMAP: carotte, concombre, tomate, épinards","Fruits: kiwi, orange, fraise, myrtilles","Noix (noix, macadamia, en petites quantités)"],"it":["Riso, quinoa, avena (porzione controllata)","Pollo, tacchino, pesce, uova","Basso lattosio: formaggi stagionati, latte senza lattosio","Verdure low-FODMAP: carota, cetriolo, pomodoro, spinaci","Frutti: kiwi, arancia, fragola, mirtilli","Frutta secca (noci, macadamia, piccole quantità)"]}',
'{"es":["Ajo y cebolla (altos en fructanos)","Manzana, pera, mango (alta fructosa)","Legumbres (judías, lentejas en fase inicial)","Trigo y centeno","Leche y yogur convencionales","Coliflor, alcachofas, espárragos"],"en":["Garlic and onion (high fructans)","Apple, pear, mango (high fructose)","Legumes (beans, lentils in initial phase)","Wheat and rye","Conventional milk and yoghurt","Cauliflower, artichokes, asparagus"],"fr":["Ail et oignon (riches en fructanes)","Pomme, poire, mangue (fructose élevé)","Légumineuses (haricots, lentilles en phase initiale)","Blé et seigle","Lait et yaourt conventionnels","Chou-fleur, artichauts, asperges"],"it":["Aglio e cipolla (ricchi di fruttani)","Mela, pera, mango (alto fruttosio)","Legumi (fagioli, lenticchie in fase iniziale)","Frumento e segale","Latte e yogurt convenzionali","Cavolfiore, carciofi, asparagi"]}',
'{"es":["Avena (en porción pequeña, max 52g)","Nueces de cajú y pistachos (porción pequeña)"],"en":["Oats (small portion, max 52g)","Cashews and pistachios (small portion)"],"fr":["Avoine (petite portion, max 52g)","Noix de cajou et pistaches (petite portion)"],"it":["Avena (piccola porzione, max 52g)","Anacardi e pistacchi (piccola porzione)"]}',
