-- ── 10. PALEO ────────────────────────────────────────────────────────────────
INSERT INTO diets (id,display_order,icon,category,name,description,allowed_foods,forbidden_foods,limited_foods,macros,benefits,warnings,compatible_goals,good_for_conditions,allergen_free,sample_day)
VALUES (
'paleo',10,'🥩','ancestral',
'{"es":"Paleo","en":"Paleo","fr":"Paléo","it":"Paleo"}',
'{"es":"Imita la dieta del paleolítico: carnes, pescados, huevos, verduras, frutas y frutos secos. Sin cereales, legumbres ni lácteos.","en":"Mimics the palaeolithic diet: meats, fish, eggs, vegetables, fruits and nuts. No grains, legumes or dairy.","fr":"Imite le régime paléolithique: viandes, poissons, œufs, légumes, fruits et noix. Sans céréales, légumineuses ni produits laitiers.","it":"Imita la dieta paleolitica: carni, pesce, uova, verdura, frutta e frutta secca. Senza cereali, legumi né latticini."}',
'{"es":["Carnes magras y de pasto","Pescados y mariscos","Huevos","Verduras (excepto patata en versión estricta)","Frutas de bajo índice glucémico","Frutos secos y semillas","Aceites naturales (oliva, coco)","Especias y hierbas"],"en":["Lean and grass-fed meats","Fish and seafood","Eggs","Vegetables (except potato in strict version)","Low-glycaemic fruits","Nuts and seeds","Natural oils (olive, coconut)","Spices and herbs"],"fr":["Viandes maigres et de pâturage","Poissons et fruits de mer","Œufs","Légumes (sauf pomme de terre en version stricte)","Fruits à faible index glycémique","Noix et graines","Huiles naturelles (olive, coco)","Épices et herbes"],"it":["Carni magre e al pascolo","Pesce e frutti di mare","Uova","Verdura (tranne patate nella versione rigorosa)","Frutta a basso indice glicemico","Frutta secca e semi","Oli naturali (oliva, cocco)","Spezie ed erbe"]}',
'{"es":["Cereales (trigo, arroz, avena, maíz)","Legumbres (judías, lentejas, garbanzos)","Lácteos","Azúcar refinado y miel","Sal en exceso","Aceites vegetales refinados","Patatas (versión estricta)"],"en":["Grains (wheat, rice, oats, corn)","Legumes (beans, lentils, chickpeas)","Dairy","Refined sugar and honey","Excess salt","Refined vegetable oils","Potatoes (strict version)"],"fr":["Céréales (blé, riz, avoine, maïs)","Légumineuses (haricots, lentilles, pois chiches)","Produits laitiers","Sucre raffiné et miel","Excès de sel","Huiles végétales raffinées","Pommes de terre (version stricte)"],"it":["Cereali (frumento, riso, avena, mais)","Legumi (fagioli, lenticchie, ceci)","Latticini","Zucchero raffinato e miele","Sale in eccesso","Oli vegetali raffinati","Patate (versione rigorosa)"]}',
'{"es":["Patata y boniato (paleo flexible)","Fruta muy dulce (plátano, uva)","Miel y sirope de arce"],"en":["Potato and sweet potato (flexible paleo)","Very sweet fruit (banana, grapes)","Honey and maple syrup"],"fr":["Pomme de terre et patate douce (paléo flexible)","Fruits très sucrés (banane, raisin)","Miel et sirop d''érable"],"it":["Patata e patata dolce (paleo flessibile)","Frutta molto dolce (banana, uva)","Miele e sciroppo d''acero"]}',
'{"carbs_pct":25,"protein_pct":30,"fat_pct":45}',
'{"es":["Mejora sensibilidad a la insulina","Reduce inflamación","Pérdida de peso eficaz a corto plazo","Sin gluten ni lácteos por naturaleza"],"en":["Improves insulin sensitivity","Reduces inflammation","Effective short-term weight loss","Naturally gluten and dairy-free"],"fr":["Améliore la sensibilité à l''insuline","Réduit l''inflammation","Perte de poids efficace à court terme","Naturellement sans gluten ni produits laitiers"],"it":["Migliora la sensibilità all''insulina","Riduce l''infiammazione","Perdita di peso efficace a breve termine","Naturalmente senza glutine e latticini"]}',
'{"es":["Baja en calcio (sin lácteos)","Difícil de mantener a largo plazo","Cara (carne de pasto)","Puede ser baja en fibra si no se consumen muchas verduras"],"en":["Low in calcium (no dairy)","Hard to maintain long-term","Expensive (grass-fed meat)","Can be low in fibre without abundant vegetables"],"fr":["Pauvre en calcium (sans produits laitiers)","Difficile à maintenir à long terme","Coûteuse (viande de pâturage)","Peut être pauvre en fibres sans beaucoup de légumes"],"it":["Bassa in calcio (senza latticini)","Difficile da mantenere a lungo termine","Costosa (carne al pascolo)","Può essere povera di fibre senza molta verdura"]}',
