-- ── 11. CETOGÉNICA (KETO) ────────────────────────────────────────────────────
INSERT INTO diets (id,display_order,icon,category,name,description,allowed_foods,forbidden_foods,limited_foods,macros,benefits,warnings,compatible_goals,good_for_conditions,avoid_for_conditions,allergen_free,sample_day)
VALUES (
'keto',11,'🥑','low-carb',
'{"es":"Cetogénica (Keto)","en":"Ketogenic (Keto)","fr":"Cétogène (Keto)","it":"Chetogenica (Keto)"}',
'{"es":"Dieta muy baja en carbohidratos (max. 20-50g/día) y alta en grasas. Induce cetosis: el cuerpo quema grasa en lugar de glucosa como fuente de energía.","en":"Very low carbohydrate (max 20-50g/day) and high fat diet. Induces ketosis: the body burns fat instead of glucose for energy.","fr":"Régime très pauvre en glucides (max 20-50g/jour) et riche en graisses. Induit la cétose: le corps brûle les graisses plutôt que le glucose.","it":"Dieta molto povera di carboidrati (max 20-50g/giorno) e ricca di grassi. Induce la chetosi: il corpo brucia grassi invece di glucosio."}',
